    <script>
        document.addEventListener("DOMContentLoaded", function () {
            // --- 图标定义 ---
            const iconSun = '☼';
            const iconMoon = '☾';
            // --- 主题切换逻辑 ---
            const themeToggle = document.getElementById('theme-toggle');
            const body = document.body;

            function updateThemeIcon() {
                const isDark = body.classList.contains('theme-dark');
                themeToggle.innerHTML = `<span>${isDark ? iconMoon : iconSun}</span>`;
                themeToggle.title = isDark ? "切换到日间模式" : "切换到夜间模式";
            }

            // 1. 初始化时，从localStorage加载主题
            const savedTheme = localStorage.getItem('branch-selector-theme') || 'theme-dark';
            body.classList.add(savedTheme);
            updateThemeIcon();

            // 2. 点击按钮切换主题
            themeToggle.addEventListener('click', (e) => {
                e.preventDefault();
                e.stopPropagation();
                if (body.classList.contains('theme-dark')) {
                    body.classList.replace('theme-dark', 'theme-light');
                    localStorage.setItem('branch-selector-theme', 'theme-light');
                } else {
                    body.classList.replace('theme-light', 'theme-dark');
                    localStorage.setItem('branch-selector-theme', 'theme-dark');
                }
                updateThemeIcon();
            });

            // --- 动态主题色同步逻辑 ---
            function hexToRgb(hex) {
                const result = /^#?([a-f\d]{2})([a-f\d]{2})([a-f\d]{2})$/i.exec(hex);
                return result ? {
                    r: parseInt(result[1], 16),
                    g: parseInt(result[2], 16),
                    b: parseInt(result[3], 16)
                } : null;
            }

            function applyThemeColor() {
                // 读取和小说标题相同的颜色配置
                const savedColor = localStorage.getItem('novel_theme_color_v2');
                if (savedColor) {
                    const rgb = hexToRgb(savedColor);
                    if (rgb) {
                        body.style.setProperty('--night-accent-hex', savedColor);
                        body.style.setProperty('--night-r', rgb.r);
                        body.style.setProperty('--night-g', rgb.g);
                        body.style.setProperty('--night-b', rgb.b);
                    }
                }
            }

            // 初始化应用一次
            applyThemeColor();

            // 监听 localStorage 的变化，实现与其他组件的实时同步
            window.addEventListener('storage', function(e) {
                if (e.key === 'novel_theme_color_v2') {
                    applyThemeColor();
                }
            });

            // 如果在一个页面内需要不经过 storage 事件强制同步，也可以挂载全局方法
            const originalSetItem = localStorage.setItem;
            localStorage.setItem = function(key, val) {
                originalSetItem.apply(this, arguments);
                if (key === 'novel_theme_color_v2') {
                    applyThemeColor();
                }
            };


            // --- 选项渲染逻辑 ---
            function init() {
                const refs = {
                    optionsContainer: document.getElementById("options-container"),
                    rawData: document.getElementById("raw-options-data"),
                };
                if (refs.rawData && refs.optionsContainer) {
                    renderOptions(refs.rawData, refs.optionsContainer);
                }
            }

            function renderOptions(rawNode, root) {
                root.innerHTML = '';
                // 解决可能存在的HTML转义问题，并按行分割
                const rawText = rawNode.innerHTML.replace(/<br\s*\/?>/gi, '\n').replace(/</g, '<').replace(/>/g, '>');

                // 支持直接通过文本节点读取或处理转义
                const lines = (rawNode.textContent || rawText).trim().split(/\r?\n/).filter(s => s.trim() !== "");

                lines.forEach((line) => {
                    // 兼容原来的格式，同时也兼容 A.xxx 这种连在一起的格式
                    // 匹配以 字母+点 开头，后面跟着任意数量空格的内容
                    let text = line.trim();
                    const match = text.match(/^([A-Z])\.\s*(.*)$/i);
                    let displayLetter = '';

                    if (match) {
                        displayLetter = match[1].toUpperCase() + '. '; // 提取字母部分作为装饰（可选使用）
                        text = match[2]; // 提取实际内容
                    }

                    if (!text) return;

                    const item = document.createElement("div");
                    item.className = "clickable-text";
                    // 传递给输入框的值（完整文字，或原样保留需要的格式）
                    item.setAttribute("data-action", text);

                    // 使用 textContent 避免 HTML 标签（如 <user>）被当成 DOM 节点解析而隐藏
                    const li = document.createElement("li");
                    li.textContent = text;
                    item.appendChild(li);

                    item.addEventListener("click", function (e) {
                        e.stopPropagation();
                        const allItems = root.querySelectorAll('.clickable-text');
                        allItems.forEach(item => item.classList.remove('selected'));
                        this.classList.add('selected');

                        const payload = this.getAttribute("data-action");
                        try {
                            const t = window.parent.document.querySelector("#send_textarea");
                            const n = window.parent.triggerSlash;
                            if (t) {
                                const v = t.value + payload;
                                if (n) { n(`/setinput ${v}`); }
                                else { t.value = v; t.dispatchEvent(new Event("input", { bubbles: true })); }
                            } else if (n) { n(`/setinput ${payload}`); }
                        } catch (err) {
                            console.error("Failed to send text to SillyTavern input:", err);
                        }
                    });
                    root.appendChild(item);
                });
            }
            init();
        });
    </script>
