    <script>
        (function () {
            // === 1. 主题切换逻辑 ===
            const app = document.getElementById('ghostCalendarApp');
            const icon = document.getElementById('themeIcon');
            const STORAGE_KEY = 'ghost-calendar-theme';
            function initTheme() {
                const savedTheme = localStorage.getItem(STORAGE_KEY);
                if (savedTheme === 'night') { app.classList.add('night-mode'); icon.textContent = '☀'; }
                else { app.classList.remove('night-mode'); icon.textContent = '☾'; }
            }
            window.toggleGhostTheme = function() {
                app.classList.toggle('night-mode');
                const isNight = app.classList.contains('night-mode');
                icon.textContent = isNight ? '☀' : '☾';
                localStorage.setItem(STORAGE_KEY, isNight ? 'night' : 'day');
            };
            initTheme();

            // === 2. 数据解析与渲染逻辑 (兼容5和6字段) ===
            const rawDataContainer = document.getElementById('calendar-raw-data-switch');
            if (!rawDataContainer) return;
            const rawString = rawDataContainer.textContent.trim();
            const lines = rawString.split(/\r?\n/);
            const calendarData = [];
            let currentDayObj = null;

            lines.forEach(line => {
                line = line.trim();
                if (!line) return;
                if (line.startsWith('Date:')) {
                    const parts = line.replace('Date:', '').split('|').map(s => s.trim());
                    if (parts.length >= 1) { currentDayObj = { dateStr: parts[0], dayName: parts[1] || '', events: [] }; calendarData.push(currentDayObj); }
                }
                else if (line.startsWith('Event:') && currentDayObj) {
                    const parts = line.replace('Event:', '').split('|').map(s => s.trim());
                    // *** 修改: 兼容5字段和6字段 ***
                    if (parts.length >= 5) { // 只要有5个基本字段就进行处理
                        currentDayObj.events.push({
                            type: parts[0], title: parts[1], description: parts[2], time: parts[3], location: parts[4],
                            npcAction: parts[5] || '' // 如果第6个字段不存在，则赋值为空字符串
                        });
                    }
                }
            });

            const scroller = document.getElementById('ghost-scroller-switch');
            const eventList = document.getElementById('ghost-list-switch');

            function getColorByType(type) { switch(type) { case 'world': return 'var(--c-world)'; case 'major': return 'var(--c-major)'; case 'user': return 'var(--c-user)'; case 'character': return 'var(--c-char)'; default: return 'currentColor'; } }
            function translateType(type) { switch(type.toLowerCase()) { case 'world': return '世界'; case 'major': return '重要'; case 'user': return '日常'; case 'character': return '羁绊'; default: return '其他'; } }

            function render() {
                scroller.innerHTML = '';
                calendarData.forEach((day, index) => {
                    const card = document.createElement('div');
                    card.className = `ghost-date-item ${index === 0 ? 'active' : ''}`;
                    const dateParts = day.dateStr.split('/');
                    const dayNum = dateParts[dateParts.length - 1];
                    let dotsHtml = '';
                    day.events.forEach(ev => { const color = getColorByType(ev.type); dotsHtml += `<div class="ghost-dot" style="background-color: ${color}"></div>`; });
                    card.innerHTML = `<span class="ghost-day-name">${day.dayName}</span><span class="ghost-day-num">${dayNum}</span><div class="ghost-dots">${dotsHtml}</div>`;
                    card.onclick = () => { scroller.querySelectorAll('.ghost-date-item').forEach(c => c.classList.remove('active')); card.classList.add('active'); renderEvents(day); };
                    scroller.appendChild(card);
                });
                if (calendarData.length > 0) renderEvents(calendarData[0]); else eventList.innerHTML = '<div class="ghost-empty">空空如也</div>';
            }

            function renderEvents(dayData) {
                eventList.innerHTML = '';
                if (dayData.events.length === 0) { eventList.innerHTML = '<div class="ghost-empty">没有安排？好好休息吧</div>'; return; }
                dayData.events.forEach(ev => {
                    const details = document.createElement('details');
                    details.className = `ghost-event-details type-${ev.type}`;
                    let typeLabel = translateType(ev.type);

                    // *** 修改: 动态生成内容区域 ***
                    let contentHtml = `<div class="ghost-event-desc">${ev.description}</div>`;
                    // 只有当 npcAction 存在且不为空时，才添加这部分HTML
                    if (ev.npcAction && ev.npcAction.trim() !== '') {
                        contentHtml += `<div class="ghost-event-npc-action">${ev.npcAction}</div>`;
                    }

                    details.innerHTML = `
                        <summary class="ghost-event-summary">
                            <div class="ghost-event-meta"><span>${ev.time}</span><span>•</span><span>${typeLabel}</span></div>
                            <div class="ghost-event-title">${ev.title}</div>
                            <div class="ghost-event-loc">@ ${ev.location}</div>
                        </summary>
                        <div class="ghost-event-content-wrapper">${contentHtml}</div>
                    `;
                    eventList.appendChild(details);
                });
            }

            render();
        })();
    </script>
</body>
</html>
