    <div class="novel-preface">$6</div>

    <script>
        (function () {
            // === 1. 初始化和功能绑定 ===
            const currentScript = document.currentScript;
            const container = currentScript.closest('.novel-header-container');

            // --- 主题切换 ---
            const themeBtn = container.querySelector('.theme-toggle-btn');
            const themeIcon = themeBtn.querySelector('.toggle-icon');
            const savedThemePref = localStorage.getItem('novel_theme_preference');
            if (savedThemePref === 'night') {
                container.classList.add('night-mode');
                themeIcon.textContent = '☽';
            }
            window.toggleNovelTheme = function(btnElement) {
                const localContainer = btnElement.closest('.novel-header-container');
                const localIcon = btnElement.querySelector('.toggle-icon');
                localContainer.classList.toggle('night-mode');
                const isNight = localContainer.classList.contains('night-mode');
                localIcon.textContent = isNight ? '☽' : '☀';
                localStorage.setItem('novel_theme_preference', isNight ? 'night' : 'day');
            };

            // --- 字体大小调整 (逻辑已更新) ---
            const increaseBtn = container.querySelector('.font-increase-btn');
            const decreaseBtn = container.querySelector('.font-decrease-btn');
            const sizeDisplay = container.querySelector('.font-size-display');

            const FONT_SCALE_STEP = 0.1;
            const MIN_FONT_SCALE = 0.7; // 对应 "壹"
            const MAX_FONT_SCALE = 1.6; // 对应 "拾"
            const DEFAULT_FONT_SCALE = 1.0;

            let currentFontScale = parseFloat(localStorage.getItem('novel_font_scale')) || DEFAULT_FONT_SCALE;

            function applyFontSize() {
                // 更新：增加了 玖 和 拾
                const scaleToChinese = {
                    "0.7": "壹", "0.8": "贰", "0.9": "叁", "1.0": "肆",
                    "1.1": "伍", "1.2": "陆", "1.3": "柒", "1.4": "捌",
                    "1.5": "玖", "1.6": "拾"
                };
                currentFontScale = Math.max(MIN_FONT_SCALE, Math.min(currentFontScale, MAX_FONT_SCALE));
                container.style.setProperty('--novel-font-scale', currentFontScale);
                const scaleKey = currentFontScale.toFixed(1);
                sizeDisplay.textContent = scaleToChinese[scaleKey] || '肆';
                localStorage.setItem('novel_font_scale', currentFontScale.toFixed(2));
            }

            increaseBtn.onclick = function() {
                if (parseFloat(currentFontScale.toFixed(1)) < MAX_FONT_SCALE) {
                    currentFontScale += FONT_SCALE_STEP;
                    applyFontSize();
                }
            };
            decreaseBtn.onclick = function() {
                if (parseFloat(currentFontScale.toFixed(1)) > MIN_FONT_SCALE) {
                    currentFontScale -= FONT_SCALE_STEP;
                    applyFontSize();
                }
            };
            applyFontSize(); // 初始加载时应用

            // === 2. 元数据渲染 (无变动) ===
            const metaContainer = container.querySelector('#novel-meta-container');
            const cpRaw = metaContainer.getAttribute('data-cp') || '';
            const locRaw = metaContainer.getAttribute('data-loc') || '';
            const cpGroups = cpRaw.split(/[,，]/).map(g => g.trim()).filter(g => g);
            const isSingleCP = cpGroups.length <= 1;

            function parseCPGroup(group) {
                const parts = group.split(/\s*([×xX&])\s*/);
                let html = '';
                parts.forEach((part, idx) => {
                    if (!part.trim()) return;
                    html += (idx % 2 === 1) 
                        ? `<span class="novel-cp-relation">${part.trim()}</span>` 
                        : `<span class="novel-cp-name">${part.trim()}</span>`;
                });
                return html;
            }

            if (isSingleCP) {
                metaContainer.innerHTML = `
                    <div class="novel-meta-single-row">
                        <div class="novel-meta-card">
                            <span class="novel-meta-label">CP</span>
                            <div class="novel-cp-inline">${cpGroups[0] ? parseCPGroup(cpGroups[0]) : '-'}</div>
                        </div>
                        <div class="novel-meta-card">
                            <span class="novel-meta-label">AT</span>
                            <span>${locRaw}</span>
                        </div>
                    </div>`;
            } else {
                let cpGroupsHTML = cpGroups.map(g => `<div class="novel-cp-group">${parseCPGroup(g)}</div>`).join('');
                metaContainer.innerHTML = `
                    <div class="novel-meta-multi-row">
                        <div class="novel-cp-row">
                            <span class="novel-cp-row-label">CP</span>
                            ${cpGroupsHTML}
                        </div>
                        <div class="novel-meta-card">
                            <span class="novel-meta-label">AT</span>
                            <span>${locRaw}</span>
                        </div>
                    </div>`;
            }

            const tagsContainer = container.querySelector('#novel-tags-container');
            if (tagsContainer) {
                const tagsRaw = tagsContainer.getAttribute('data-tags') || '';
                const tags = tagsRaw.split(/[\/，,]/).map(t => t.trim()).filter(t => t);
                tagsContainer.innerHTML = '';
                tags.forEach(tag => {
                    const span = document.createElement('span');
                    span.className = 'novel-tag';
                    span.textContent = tag;
                    tagsContainer.appendChild(span);
                });
            }
        })();
    </script>
</div>
</body>
</html>
