        reader.onload = function (ev) {
          try {
            const imported = JSON.parse(ev.target.result);
            if (typeof imported === "object" && imported !== null) {
              settings = { ...settings, ...imported };
              saveSettings();
              applyBallAppearance();
              applyThemeFromBallColor();
              window.parent
