            --th-mp-bg: linear-gradient(145deg, rgba(31, 31, 34, 0.75), rgba(22, 22, 24, 0.75));
            --th-mp-border: #c3073f;
            --th-mp-accent: #c3073f;
            --th-mp-accent-dark: #6f2232;
            --th-mp-accent-light: #d11e48;
            --th-mp-text: #f5f5f5;
            --th-mp-subtext: #b0b0b0;
            --th-mp-shadow: rgba(195, 7, 63, 0.4);
            --th-mp-list-hover: rgba(111, 34, 50, 0.6);
            --th-mp-list-active: rgba(195, 7, 63, 0.2);
            --th-mp-love-pink: #ff2a6d;

            --th-mp-white: #f5f5f5;
            --th-mp-white-alpha-05: rgba(245, 245, 245, 0.05);
            --th-mp-white-alpha-10: rgba(245, 245, 245, 0.1);
            --th-mp-white-alpha-50: rgba(245, 245, 245, 0.5);
            --th-mp-white-alpha-80: rgba(245, 245, 245, 0.8);
        }

        .th-music-player.theme-qingdai {
            --th-mp-bg: linear-gradient(135deg, rgba(28, 35, 41, 0.95), rgba(35, 45, 55, 0.9));
            --th-mp-border: rgba(255, 255, 255, 0.1);
            --th-mp-accent: #cbb488;
            --th-mp-accent-dark: #8c7a5b;
            --th-mp-accent-light: #e6d5b8;
            --th-mp-text: #f0f2f5;
            --th-mp-subtext: #8b96a1;
            --th-mp-shadow: rgba(0, 0, 0, 0.5);
            --th-mp-list-hover: rgba(203, 180, 136, 0.15);
            --th-mp-list-active: rgba(203, 180, 136, 0.08);
            --th-mp-white: #f0f2f5;
            --th-mp-white-alpha-05: rgba(240, 242, 245, 0.05);
            --th-mp-white-alpha-10: rgba(240, 242, 245, 0.1);
            --th-mp-white-alpha-50: rgba(240, 242, 245, 0.5);
            --th-mp-white-alpha-80: rgba(240, 242, 245, 0.8);
            --th-mp-black: #1c2329;
            --th-mp-black-alpha-20: rgba(28, 35, 41, 0.2);
            --th-mp-black-alpha-30: rgba(28, 35, 41, 0.3);
            --th-mp-black-alpha-50: rgba(28, 35, 41, 0.5);
            --th-mp-love-pink: #b53d3d;
        }

        .th-music-player.theme-xuansha {
            --th-mp-bg: linear-gradient(135deg, rgba(242, 240, 233, 0.95), rgba(230, 228, 213, 0.95));
            --th-mp-border: #d4d2c9;
            --th-mp-accent: #ba3d3d;
            --th-mp-accent-dark: #8f2b2b;
            --th-mp-accent-light: #d95f5f;
            --th-mp-text: #2c3e50;
            --th-mp-subtext: #666d75;
            --th-mp-shadow: rgba(44, 62, 80, 0.15);
            --th-mp-list-hover: rgba(186, 61, 61, 0.08);
            --th-mp-list-active: rgba(186, 61, 61, 0.04);
            --th-mp-white: #2c3e50;
            --th-mp-white-alpha-05: rgba(44, 62, 80, 0.05);
            --th-mp-white-alpha-10: rgba(44, 62, 80, 0.1);
            --th-mp-white-alpha-50: rgba(44, 62, 80, 0.5);
            --th-mp-white-alpha-80: rgba(44, 62, 80, 0.8);
            --th-mp-black: #1c2329;
            --th-mp-black-alpha-20: rgba(0, 0, 0, 0.1);
            --th-mp-black-alpha-30: rgba(0, 0, 0, 0.15);
            --th-mp-black-alpha-50: rgba(0, 0, 0, 0.25);
            --th-mp-love-pink: #ba3d3d;
        }

        .th-music-player.theme-dihua {
            --th-mp-bg: linear-gradient(135deg, rgba(255, 255, 255, 0.88), rgba(245, 245, 245, 0.82));
            --th-mp-border: #9d9d9d;
            --th-mp-accent: #515151;
            --th-mp-accent-dark: #121212;
            --th-mp-accent-light: #9d9d9d;
            --th-mp-text: #878787;
            --th-mp-subtext: #707070;
            --th-mp-shadow: rgba(0, 0, 0, 0.08);
            --th-mp-list-hover: rgba(18, 18, 18, 0.05);
            --th-mp-list-active: rgba(18, 18, 18, 0.08);
            --th-mp-white: #242424;
            --th-mp-white-alpha-05: rgba(18, 18, 18, 0.05);
            --th-mp-white-alpha-10: rgba(18, 18, 18, 0.1);
            --th-mp-white-alpha-50: rgba(18, 18, 18, 0.5);
            --th-mp-white-alpha-80: rgba(18, 18, 18, 0.8);
            --th-mp-black: #242424;
            --th-mp-black-alpha-20: rgba(18, 18, 18, 0.1);
            --th-mp-black-alpha-30: rgba(18, 18, 18, 0.15);
            --th-mp-black-alpha-50: rgba(18, 18, 18, 0.25);
        }

        /* 歌词悬浮显示 */
        .th-mp-floating-lyrics {
            position: absolute;
            /* 位置由 js 动态控制类名决定 */
            white-space: normal;
            width: max-content;
            max-width: 250px;
            line-height: 1.3;
            padding: 4px 12px;
            font-size: 14px;
            font-weight: bold;
            color: var(--th-mp-text);
            pointer-events: none;
            opacity: 0;
            transition: opacity 0.5s, top 0.3s, bottom 0.3s, left 0.3s, right 0.3s, color 0.3s, transform 0.4s cubic-bezier(0.34, 1.56, 0.64, 1);
            text-shadow: 0 0 4px var(--th-mp-accent-dark), 0 0 8px var(--th-mp-black-alpha-50);
            z-index: 0;
            display: flex;
            flex-direction: column;
            align-items: center;
            gap: 2px;
        }

        /* 悬浮歌词位置变体 */
        .th-mp-floating-lyrics.pos-bottom {
            top: 65px; left: 50%; transform: translateX(-50%); text-align: center; transform-origin: top center;
        }
        .th-mp-floating-lyrics.pos-top {
            bottom: 65px; left: 50%; transform: translateX(-50%); text-align: center; transform-origin: bottom center;
        }
        .th-mp-floating-lyrics.pos-left {
            right: 65px; top: 50%; transform: translateY(-50%); align-items: flex-end; text-align: right; transform-origin: right center;
        }
        .th-mp-floating-lyrics.pos-right {
            left: 65px; top: 50%; transform: translateY(-50%); align-items: flex-start; text-align: left; transform-origin: left center;
        }

        /* 悬浮歌词颜色变体 */
        .th-mp-floating-lyrics.theme-light {
            color: var(--th-mp-text);
            text-shadow: 0 0 4px var(--th-mp-accent-dark), 0 0 8px var(--th-mp-black-alpha-50);
        }
        .th-mp-floating-lyrics.theme-dark {
            color: var(--th-mp-black);
            text-shadow: 0 0 4px var(--th-mp-white-alpha-80), 0 0 8px var(--th-mp-white-alpha-50);
        }

        .th-mp-float-line-sub {
             font-size: 10px;
             opacity: 0.8;
             font-weight: normal;
        }

        .th-music-player.collapsed.lyrics-on .th-mp-floating-lyrics {
            opacity: 1;
        }

        /* PV 文字动效 */
        .th-pv-char {
            display: inline-block;
            opacity: 0;
            vertical-align: text-bottom; /* 优化基线对齐 */
            animation: pv-char-in 0.6s cubic-bezier(0.22, 1, 0.36, 1) forwards;
            will-change: transform, opacity, filter;
        }

        @keyframes pv-char-in {
            0% {
                opacity: 0;
                transform: translate(var(--rx), var(--ry)) scale(1.2) rotate(var(--rr));
                filter: blur(8px);
            }
            100% {
                opacity: 1;
                transform: translate(0, 0) scale(1) rotate(0);
                filter: blur(0);
            }
        }

        /* 歌词面板样式 */
        .th-mp-lyrics-panel {
             position: absolute;
             top: 70px;
             left: 0;
             right: 0;
             height: 0; /* 默认收起 */
             background: var(--th-mp-bg);
             border-radius: 12px;
             padding: 0; /* 默认无内边距 */
             display: flex;
             opacity: 0;
             visibility: hidden;
             flex-direction: column;
             align-items: center;
             overflow: hidden;
             box-shadow: none; /* 默认无阴影 */
             z-index: 10001;
             text-align: center;
             transition: all 0.4s cubic-bezier(0.34, 1.56, 0.64, 1);
             transform: translateY(-20px) scale(0.95);
             pointer-events: none;
        }

        /* 歌词面板顶部工具栏 */
        .th-mp-lyrics-toolbar {
            position: absolute;
            top: 5px;
            right: 5px;
            display: flex;
            gap: 6px; /* 减小间距 */
            opacity: 0.6;
            transition: opacity 0.2s;
            pointer-events: auto;
            z-index: 10003;
        }
        .th-mp-lyrics-toolbar:hover { opacity: 1; }

        .th-mp-tool-btn {
            background: none;
            border: none;
            color: var(--th-mp-subtext);
            cursor: pointer;
            padding: 3px;
            border-radius: 50%;
            display: flex;
            align-items: center;
            justify-content: center;
            transition: all 0.2s;
            pointer-events: auto;
        }
        .th-mp-tool-btn:hover {
            background: var(--th-mp-white-alpha-10);
            color: var(--th-mp-text);
            transform: scale(1.1);
        }
        .th-mp-tool-btn svg {
            width: 18px; height:18px;
            fill: none;
            stroke: currentColor;
            stroke-width: 2;
            stroke-linecap: round;
            stroke-linejoin: round;
        }

        .th-mp-lyrics-panel.show {
            opacity: 1;
            visibility: visible;
            transform: translateY(0) scale(1);
            pointer-events: auto;
            height: 140px; /* 展开高度 */
            padding: 10px 0;
            box-shadow: 0 6px 20px var(--th-mp-shadow);
        }

        .th-mp-lyrics-content {
            width: 100%;
            height: 100%;
            overflow: hidden;
            font-size: 13px;
            color: var(--th-mp-subtext);
            /* 隐藏滚动条 */
            scrollbar-width: none;
            -ms-overflow-style: none;
            mask-image: linear-gradient(to bottom, transparent 0%, black 20%, black 80%, transparent 100%);
            -webkit-mask-image: linear-gradient(to bottom, transparent 0%, black 20%, black 80%, transparent 100%);
            padding: 0;
            position: relative;
        }

        .th-mp-lyrics-content::-webkit-scrollbar {
            display: none;
        }

        .th-mp-lyrics-line {
            padding: 6px 10px;
            transition: all 0.5s cubic-bezier(0.25, 0.46, 0.45, 0.94);
            line-height: 1.4;
            opacity: 0.5;
            transform: scale(0.95);
            filter: blur(0.5px);
        }

        .th-mp-lyrics-line.active {
            color: var(--th-mp-text);
            font-weight: bold;
            opacity: 1;
            transform: scale(1.05);
            filter: blur(0);
        }

        /* 彩蛋样式 */
        .th-mp-lyrics-tint {
             color: var(--th-mp-love-pink) !important;
             text-shadow: 0 0 8px var(--th-mp-love-pink) !important;
             font-weight: bold;
        }

        .th-mp-btn.active {
            color: var(--th-mp-accent);
            text-shadow: 0 0 5px var(--th-mp-accent);
        }

        .th-music-player {
            position: fixed;
            bottom: 100px;
            right: 50px;
            background: var(--th-mp-bg);
            box-shadow: 0 4px 15px var(--th-mp-shadow), inset 0 1px 3px var(--th-mp-white-alpha-05);
            z-index: 10000;
            color: var(--th-mp-text);
            font-family: 'Georgia', 'Segoe UI', serif;
            transition: width 0.4s cubic-bezier(0.34, 1.56, 0.64, 1),
                        height 0.4s cubic-bezier(0.34, 1.56, 0.64, 1),
                        padding 0.4s cubic-bezier(0.34, 1.56, 0.64, 1),
                        margin 0.4s cubic-bezier(0.34, 1.56, 0.64, 1),
                        background 0.4s, box-shadow 0.4s, border-radius 0.4s,
                        transform 0.4s cubic-bezier(0.34, 1.56, 0.64, 1),
                        opacity 0.4s;
            display: flex;
            align-items: center;
            overflow: visible;
            height: 60px;
            border-radius: 30px;
            padding: 0;
            user-select: none;
            box-sizing: border-box;
        }

        /* 收起状态 (圆形) */
        .th-music-player.collapsed {
            width: 60px;
            cursor: move;
        }

        /* 闲置缩小状态 (仅在收起时生效) */
        .th-music-player.collapsed.mini {
            transform: scale(0.8);
            box-shadow: none;
        }
        .th-music-player.collapsed.mini:hover {
            transform: scale(1);
            opacity: 1;
            box-shadow: 0 4px 15px var(--th-mp-shadow);
        }

        /* 展开状态 (胶囊) */
        .th-music-player.expanded {
            width: 340px;
            padding-right: 24px;
        }

        .th-music-player.expand-left {
            flex-direction: row-reverse;
        }

        .th-music-player.expand-left.expanded {
            padding-right: 0;
            padding-left: 24px;
        }

        /* 封面区域 */
        .th-mp-cover-wrapper {
            width: 60px;
            height: 60px;
            flex-shrink: 0;
            position: relative;
            cursor: pointer;
            z-index: 2;
            -webkit-touch-callout: none;
            -webkit-user-select: none;
            user-select: none;
        }

        .th-mp-cover {
            width: 100%;
            height: 100%;
            border-radius: 50%;
            background: linear-gradient(135deg, var(--th-mp-accent-dark), var(--th-mp-accent-light));
            background-size: cover;
            background-position: center;
            border: none;
            box-shadow: 0 4px 12px var(--th-mp-shadow), inset 0 1px 4px var(--th-mp-white-alpha-10);
            display: flex;
            align-items: center;
            justify-content: center;
            transition: transform 0.3s ease;
        }

        .th-mp-cover svg {
            width: 24px;
            height: 24px;
            fill: var(--th-mp-white-alpha-80);
            filter: drop-shadow(0 2px 4px var(--th-mp-black-alpha-30));
        }

        /* 旋转动画 */
        .th-music-player.playing .th-mp-cover {
            animation: spin 6s linear infinite;
        }

        @keyframes spin { 100% { transform: rotate(360deg); } }

        /* 主题按钮（展开时显示） */
        .th-mp-theme-float-btn {
            position: absolute;
            /* 位于圆圈左下角外侧一点的位置 */
            bottom: -5px;
            left: -5px;
            width: 24px;
            height: 24px;
            border-radius: 50%;
            background: var(--th-mp-bg);
            border: 1px solid var(--th-mp-border);
            color: var(--th-mp-subtext);
            display: flex;
            align-items: center;
            justify-content: center;
            cursor: pointer;
            z-index: 10;
            opacity: 0;
            pointer-events: none;
            transform: scale(0.5);
            transition: all 0.3s cubic-bezier(0.34, 1.56, 0.64, 1);
            box-shadow: 0 2px 5px var(--th-mp-shadow);
        }

        /* 展开且非迷你模式时显示主题按钮 */
        .th-music-player.expanded .th-mp-theme-float-btn {
            opacity: 1;
            pointer-events: auto;
            transform: scale(1);
        }

        .th-music-player.expand-left .th-mp-theme-float-btn {
            left: auto;
            right: -5px;
        }

        .th-mp-theme-float-btn:hover {
            color: var(--th-mp-accent);
            border-color: var(--th-mp-accent);
            transform: scale(1.1);
        }

        .th-mp-theme-float-btn svg {
            width: 14px;
            height: 14px;
            fill: currentColor;
        }

        /* 音波扩散动效 (多层) */
        .th-mp-wave {
            position: absolute;
            top: 50%; left: 50%;
            transform: translate(-50%, -50%);
            width: 100%; height: 100%;
            pointer-events: none;
            z-index: 1;
        }

        .th-mp-wave span {
            position: absolute;
            top: 50%; left: 50%;
            transform: translate(-50%, -50%);
            width: 100%; height: 100%;
            border-radius: 50%;
            border: 1px solid var(--th-mp-subtext);
            opacity: 0;
        }

        .th-music-player.collapsed.playing .th-mp-wave span {
            animation: ripple 3s infinite cubic-bezier(0.25, 0.46, 0.45, 0.94);
        }

        .th-music-player.collapsed.playing .th-mp-wave span:nth-child(1) { animation-delay: 0s; }
        .th-music-player.collapsed.playing .th-mp-wave span:nth-child(2) { animation-delay: 1s; }
        .th-music-player.collapsed.playing .th-mp-wave span:nth-child(3) { animation-delay: 2s; }

        @keyframes ripple {
            0% { width: 100%; height: 100%; opacity: 0.5; border-width: 1.5px; }
            100% { width: 220%; height: 220%; opacity: 0; border-width: 0px; }
        }

        /* 信息与控制区域 */
        .th-mp-body {
            flex: 1;
            display: flex;
            flex-direction: column;
            justify-content: center;
            overflow: hidden;
            margin-left: 16px;
            opacity: 1;
            transition: opacity 0.3s ease 0.1s;
        }

        .th-music-player.expand-left .th-mp-body {
            margin-left: 0;
            margin-right: 16px;
        }

        .th-music-player.collapsed .th-mp-body {
            opacity: 0;
            pointer-events: none;
            width: 0;
            margin: 0;
        }

        .th-mp-info {
            display: flex;
            flex-direction: row; /* 同一行 */
            align-items: baseline;
            gap: 6px;
            margin-bottom: 6px;
            cursor: move;
            white-space: nowrap;
            overflow: hidden;
        }

        .th-mp-title {
            font-size: 14px;
            font-weight: bold;
            color: var(--th-mp-text);
            text-shadow: 0 1px 2px var(--th-mp-black-alpha-30);
        }

        .th-mp-artist {
            font-size: 11px;
            color: var(--th-mp-subtext);
            overflow: hidden;
            text-overflow: ellipsis;
        }

        .th-mp-controls {
            display: flex;
            align-items: center;
            justify-content: space-between;
            gap: 5px;
        }

        .th-mp-btn {
            background: transparent;
            border: none;
            color: var(--th-mp-subtext);
            cursor: pointer;
            padding: 5px;
            border-radius: 50%;
            display: flex;
            align-items: center;
            justify-content: center;
            transition: all 0.2s;
        }

        .th-mp-btn:hover {
            color: var(--th-mp-white);
            background: var(--th-mp-white-alpha-10);
            transform: scale(1.1);
        }

        .th-mp-btn svg {
            width: 18px;
            height: 18px;
            fill: currentColor;
            filter: drop-shadow(0 1px 2px var(--th-mp-black-alpha-20));
        }

        /* 播放列表下拉面板*/
        .th-mp-playlist {
            position: absolute;
            top: 70px;
            left: 0;
            right: 0;
            background: var(--th-mp-bg);
            border-radius: 12px;
            padding: 0; /* 默认无内边距 */
            display: flex;
            flex-direction: column;
            max-height: 0; /* 默认收起 */
            overflow: hidden;
            box-shadow: none; /* 默认无阴影 */
            opacity: 0;
            visibility: hidden;
            transform: translateY(-10px);
            transition: all 0.3s ease;
            z-index: 10002; /* 比歌词高 */
        }

        /* 当歌词面板打开时，播放列表顺延往下 */
        .th-music-player.lyrics-on .th-mp-playlist {
             top: 220px;
        }

        .th-mp-playlist.show {
            opacity: 1;
            visibility: visible;
            transform: translateY(0);
            max-height: 240px;
            padding: 8px 0;
            box-shadow: 0 6px 20px var(--th-mp-shadow);
        }

        .th-mp-playlist-input-area {
            display: flex;
            padding: 0 12px 8px 12px;
            gap: 8px;
            border-bottom: 1px solid var(--th-mp-white-alpha-10);
            margin-bottom: 4px;
            flex-shrink: 0;
        }

        .th-mp-add-input {
            flex: 1;
            background: var(--th-mp-white-alpha-05);
            border: 1px solid var(--th-mp-white-alpha-10);
            border-radius: 6px;
            color: var(--th-mp-text);
            font-size: 11px;
            padding: 4px 6px;
            resize: none;
            outline: none;
            font-family: inherit;
        }
        .th-mp-add-input:textarea {
            box-shadow: none !important;
        }
        .th-mp-add-input::placeholder {
            color: var(--th-mp-subtext);
            opacity: 0.6;
        }
        .th-mp-add-input:focus {
            border-color: var(--th-mp-accent);
            background: var(--th-mp-white-alpha-10);
        }

        .th-mp-add-btn {
            background: var(--th-mp-accent);
            color: var(--th-mp-white);
            border: none;
            border-radius: 6px;
            width: 30px;
            cursor: pointer;
            font-size: 16px;
            font-weight: bold;
            display: flex;
            align-items: center;
            justify-content: center;
            transition: all 0.2s;
            padding: 0;
        }
        .th-mp-add-btn:hover {
            background: var(--th-mp-accent-light);
            transform: scale(1.05);
        }
        .th-mp-add-btn:active {
            transform: scale(0.95);
        }
        .th-mp-add-btn svg {
            width: 16px;
            height: 16px;
            fill: currentColor;
        }

        .th-mp-playlist-list {
            flex: 1;
            overflow-y: auto;
            display: flex;
            flex-direction: column;
        }

        .th-mp-playlist-item {
            padding: 6px 12px;
            font-size: 12px;
            color: var(--th-mp-subtext);
            cursor: pointer;
            transition: background 0.2s;
            display: flex;
            justify-content: space-between;
            align-items: center;
            gap: 10px;
        }

        .th-mp-playlist-item:hover {
            background: var(--th-mp-list-hover);
            color: var(--th-mp-text);
        }

        .th-mp-playlist-item.active {
            color: var(--th-mp-accent);
            font-weight: bold;
            background: var(--th-mp-list-active);
        }

        .th-mp-playlist-info {
             display: flex;
             flex: 1;
             gap: 8px;
             align-items: baseline;
             overflow: hidden;
        }

        .th-mp-playlist-del {
            width: 24px;
            height: 24px;
            display: flex;
            align-items: center;
            justify-content: center;
            border-radius: 4px;
            opacity: 0;
            transition: all 0.2s;
            flex-shrink: 0;
        }
        /* 移动端适配：触摸设备或小屏幕始终显示删除按钮 */
        @media (pointer: coarse), (max-width: 768px) {
            .th-mp-playlist-del { opacity: 0.6; }
            /* 修正移动端默认位置 */
            .th-music-player {
                top: 120px;
                right: 10px;
                bottom: auto;
            }
        }
        .th-mp-playlist-item:hover .th-mp-playlist-del { opacity: 0.8; }
        .th-mp-playlist-del:hover {
            opacity: 1 !important;
            background: var(--th-mp-white-alpha-10);
            color: var(--th-mp-accent);
        }
        .th-mp-playlist-del svg { width: 16px; height: 16px; fill: currentColor; }

        .th-mp-playlist-list::-webkit-scrollbar { width: 4px; }
        .th-mp-playlist-list::-webkit-scrollbar-thumb { background: var(--th-mp-accent-dark); border-radius: 2px; }

        /* 主题切换横向滚轮面板 */
        .th-mp-theme-panel {
            position: absolute;
            bottom: 70px;
            left: 50%;
            transform: translateX(-50%) translateY(10px) scale(0.9);
            background: var(--th-mp-bg);
            padding: 0 calc(50% - 25px);
            border-radius: 20px;
            display: flex;
            flex-direction: row;
            gap: 0px;
            opacity: 0;
            visibility: hidden;
            transition: opacity 0.3s, transform 0.3s, visibility 0.3s;
            box-shadow: none;
            z-index: 10005;
            pointer-events: none;
            width: 180px; /* 更窄 */
            overflow-x: auto;
            overflow-y: hidden;
            height: 36px; /* 更矮 */
            scrollbar-width: none;
            -ms-overflow-style: none;
            align-items: center;
            justify-content: flex-start;
            backdrop-filter: blur(10px);
            border: 1px solid var(--th-mp-white-alpha-10);
            /* 更柔和的边缘渐隐 */
            mask-image: linear-gradient(to right, transparent 0%, black 20%, black 80%, transparent 100%);
            -webkit-mask-image: linear-gradient(to right, transparent 0%, black 20%, black 80%, transparent 100%);
            scroll-snap-type: x mandatory;
            scroll-behavior: smooth;
            -webkit-overflow-scrolling: touch; /* 开启 iOS 惯性滚动 */
        }
        .th-mp-theme-panel::-webkit-scrollbar {
            display: none;
        }
        .th-mp-theme-panel.show {
            opacity: 1;
            visibility: visible;
            transform: translateX(-50%) translateY(0) scale(1);
            pointer-events: auto;
            box-shadow: 0 4px 15px var(--th-mp-shadow);
        }
        .th-mp-theme-item {
            padding: 0;
            font-size: 11px; /* 更小字号 */
            color: var(--th-mp-subtext);
            cursor: pointer;
            text-align: center;
            white-space: nowrap;
            flex-shrink: 0;
            scroll-snap-align: center;
            opacity: 0.5;
            transform: scale(0.85);
            /* 移除 transform 的 transition，由 JS 驱动更丝滑 */
            transition: color 0.2s, text-shadow 0.2s, opacity 0.1s linear;
            width: 50px;
            height: 100%;
            display: flex;
            justify-content: center;
            align-items: center;
        }
        .th-mp-theme-item:hover {
            color: var(--th-mp-text);
        }
        .th-mp-theme-item.active {
            color: var(--th-mp-accent) !important;
            font-weight: bold;
            text-shadow: 0 0 8px var(--th-mp-accent);
        }
    `;

