    function normalizeStr(str) {
        if (!str) return '';
        let res = '';
        for (let i = 0; i < str.length; i++) {
            const char = str[i];
            const idx = T_CHARS.indexOf(char);
            res += (idx !== -1) ? S_CHARS[idx] : char;
        }
        return res.toLowerCase();
    }

    // --- 变量存储辅助函数 ---
    function getScriptVar(key, defaultValue) {
        if (typeof getVariables === 'function') {
            try {
                const vars = getVariables({ type: 'script' });
                return (vars && vars[key] !== undefined) ? vars[key] : defaultValue;
            } catch(e) {}
        }
        if (typeof window.TavernHelper !== 'undefined') {
             const vars = window.TavernHelper.getVariables({ type: 'script' });
             return (vars && vars[key] !== undefined) ? vars[key] : defaultValue;
        }
        if (typeof window.parent !== 'undefined' && typeof window.parent.TavernHelper !== 'undefined') {
             const vars = window.parent.TavernHelper.getVariables({ type: 'script' });
             return (vars && vars[key] !== undefined) ? vars[key] : defaultValue;
        }
        return defaultValue;
    }

    function setScriptVar(key, value) {
        if (typeof updateVariablesWith === 'function') {
             try {
                updateVariablesWith(vars => {
                    vars[key] = value;
                    return vars;
                }, { type: 'script' });
                return;
             } catch(e) {}
        }
        if (typeof window.TavernHelper !== 'undefined') {
            window.TavernHelper.updateVariablesWith(vars => {
                vars[key] = value;
                return vars;
            }, { type: 'script' });
            return;
        }
        if (typeof window.parent !== 'undefined' && typeof window.parent.TavernHelper !== 'undefined') {
            window.parent.TavernHelper.updateVariablesWith(vars => {
                vars[key] = value;
                return vars;
            }, { type: 'script' });
            return;
        }
    }
