    // 创建 UI
    function createPlayerUI() {
        console.log('[MusicPlayer] Creating UI...');
        const old = doc.getElementById(PLAYER_ID);
        if (old) old.remove();

        const player = doc.createElement('div');
        player.id = PLAYER_ID;

        try {
            const scriptId = typeof getScriptId === 'function' ? getScriptId() : null;
            if (scriptId) player.setAttribute('script_id', scriptId);
        } catch (e) {}

        // 构建 class
        let themeClass = '';
        if (currentTheme === 'blue') themeClass = ' theme-blue';
        else if (currentTheme === 'daydream') themeClass = ' theme-daydream';
        else if (currentTheme === 'crimson') themeClass = ' theme-crimson';
        else if (currentTheme === 'qingdai') themeClass = ' theme-qingdai';
        else if (currentTheme === 'xuansha') themeClass = ' theme-xuansha';
        else if (currentTheme === 'dihua') themeClass = ' theme-dihua';

        player.className = `th-music-player collapsed${isLyricsEnabled ? ' lyrics-on' : ''}${themeClass}`;

        // 恢复上次位置
        const savedPos = getScriptVar('pos', null);
        if (savedPos) {
            const viewportWidth = doc.documentElement.clientWidth || window.parent.innerWidth || window.innerWidth;
            const viewportHeight = doc.documentElement.clientHeight || window.parent.innerHeight || window.innerHeight;

            // 安全恢复坐标，强制限制在当前屏幕尺寸内，防止彻底飞出视窗
            const getSafePx = (val, max) => {
                if (!val || val === 'auto') return 'auto';
                let num = parseFloat(val);
                if (isNaN(num)) return 'auto';
                if (num < 0) num = 0;
                if (num > max - 60) num = max - 60;
                return `${num}px`;
            };

            const safeTop = getSafePx(savedPos.top, viewportHeight);

            if (safeTop !== 'auto') {
                player.style.top = safeTop;

                if (savedPos.right && savedPos.right !== 'auto') {
                    player.style.right = getSafePx(savedPos.right, viewportWidth);
                    player.style.left = 'auto';
                } else if (savedPos.left && savedPos.left !== 'auto') {
                    player.style.left = getSafePx(savedPos.left, viewportWidth);
                    player.style.right = 'auto';
                } else {
                    player.style.right = '50px';
                    player.style.bottom = '100px';
                }
                player.style.bottom = 'auto';
            } else {
                setScriptVar('pos', null);
            }
        }

        player.innerHTML = `
