        }
        if(UI.lrcThemeBtn) {
            UI.lrcThemeBtn.addEventListener('click', toggleLyricsTheme);
            UI.lrcThemeBtn.addEventListener('pointerdown', (e) => e.stopPropagation()); // 防止触发拖拽
        }

        // 绑定输入框事件
        if (UI.addBtn) {
            UI.addBtn.onclick = async (e) => {
                e.stopPropagation();
                if (!UI.addInput) return;
                const text = UI.addInput.value;
                if (!text.trim()) return;

                // 优先识别网易云分享歌单的链接
                const idMatch = text.match(/music\.163\.com.*?(?:id=)(\d+)/i);
                if (idMatch) {
                    const playlistId = idMatch[1];
                    UI.addBtn.disabled = true;
                    UI.addBtn.innerHTML = '...';

                    const success = await parseAndAddPlaylist(playlistId);

                    UI.addBtn.disabled = false;
                    UI.addBtn.innerHTML = '+';

                    if (success) {
                        UI.addInput.value = '';
                    }
                    return;
                }

                // 未匹配到歌单，执行原本的逐行添加逻辑
                const lines = text.split('\n');
                let addedCount = 0;
                let firstNewKey = null;

                lines.forEach(line => {
                    if (!line.trim()) return;
                    const parts = line.split('+');
                    if (parts.length >= 2) {
                        const title = parts[0].trim();
                        const artist = parts.slice(1).join('+').trim();
                        if (title && artist) {
                            const newKey = addMusicToPlaylist(title, artist, true);
                            if (newKey && !firstNewKey) firstNewKey = newKey;
                            addedCount++;
                        }
                    } else if (parts.length === 1 && parts[0].trim()) {
                        const title = parts[0].trim();
                        const newKey = addMusicToPlaylist(title, '', true);
                        if (newKey && !firstNewKey) firstNewKey = newKey;
                        addedCount++;
                    }
                });

                if (addedCount > 0) {
                    UI.addInput.value = '';
                    renderPlaylist();
                    if (typeof toastr !== 'undefined') toastr.success(`已成功添加 ${addedCount} 首歌曲`);

                    if ((!bgmPlayer || bgmPlayer.paused) && isPlayerVisible && firstNewKey) {
                        playTrackByKey(firstNewKey);
                    }
                } else {
                    if (typeof toastr !== 'undefined') toastr.warning('格式不正确，请使用“歌名+歌手”');
                }
            };
            UI.addBtn.onpointerdown = (e) => e.stopPropagation();
        }

        if (UI.exportBtn) {
            UI.exportBtn.onclick = async (e) => {
                e.stopPropagation();

                const keys = Object.keys(MUSIC_CONFIG).filter(k => k !== 'null');
                if (keys.length === 0) {
                    if (typeof toastr !== 'undefined') toastr.warning('当前播放列表为空');
                    return;
                }

                const exportText = keys.map(k => {
                    const track = MUSIC_CONFIG[k];
                    if (!track.title) return '';
                    return track.artist ? `${track.title}+${track.artist}` : track.title;
                }).filter(text => text.trim() !== '').join('\n');

                try {
                    // 优先尝试剪贴板 API
                    await navigator.clipboard.writeText(exportText);
                    if (typeof toastr !== 'undefined') toastr.success('已将当前歌单复制到剪贴板');
                } catch (err) {
                    // 后备方案
                    const textarea = doc.createElement('textarea');
                    textarea.value = exportText;
                    textarea.style.position = 'fixed';
                    textarea.style.opacity = '0';
                    doc.body.appendChild(textarea);
                    textarea.select();
                    try {
                        doc.execCommand('copy');
                        if (typeof toastr !== 'undefined') toastr.success('已将当前歌单复制到剪贴板');
                    } catch (err2) {
                        if (typeof toastr !== 'undefined') toastr.error('复制失败，请手动复制输入框的内容');
                        if (UI.addInput) UI.addInput.value = exportText;
                    }
                    doc.body.removeChild(textarea);
                }
            };
            UI.exportBtn.onpointerdown = (e) => e.stopPropagation();
        }

        if (UI.addInput) {
            UI.addInput.onpointerdown = (e) => e.stopPropagation();
            UI.addInput.onkeydown = (e) => e.stopPropagation();
            UI.addInput.onkeyup = (e) => e.stopPropagation();
            UI.addInput.onkeypress = (e) => e.stopPropagation();
