        if(UI.modeBtn) UI.modeBtn.onclick = cycleMode;
        if(UI.prevBtn) UI.prevBtn.onclick = () => switchTrack('prev');
        if(UI.nextBtn) UI.nextBtn.onclick = () => switchTrack('next');
        if(UI.listBtn) UI.listBtn.onclick = togglePlaylist;
        if(UI.lyricsBtn) UI.lyricsBtn.onclick = toggleLyrics;

        if (UI.themeBtn) {
