        });

        // 滚轮横向滚动支持与动效
        if (UI.themePanel) {
            UI.themePanel.addEventListener('wheel', (e) => {
                e.preventDefault();
                UI.themePanel.scrollLeft += e.deltaY;
            }, { passive: false });

            UI.themePanel.addEventListener('pointerdown', (e) => e.stopPropagation());

            // 监听滚动以更新样式 (涵盖鼠标滚轮和触摸滚动)
            let themeRafId = null;
            const requestThemeUpdate = () => {
                if (!themeRafId) {
                    themeRafId = requestAnimationFrame(() => {
