    // 切换悬浮歌词位置
    function toggleLyricsPosition(e) {
        e.stopPropagation();

        const oldPos = lyricsConfig.position;
        const positions = ['bottom', 'top', 'left', 'right'];

        let idx = positions.indexOf(oldPos);
        idx = (idx + 1) % positions.length;
        const newPos = positions[idx];

        lyricsConfig.position = newPos;
        setScriptVar('lyrics_config', lyricsConfig);

        if (UI.lrcPosBtn) UI.lrcPosBtn.innerHTML = ICONS[`pos_${newPos}`];

        if (UI.floatLyricsText) {
