    // 切换悬浮歌词主题
    function toggleLyricsTheme(e) {
        e.stopPropagation();
        lyricsConfig.theme = lyricsConfig.theme === 'light' ? 'dark' : 'light';
        setScriptVar('lyrics_config', lyricsConfig);

        if (UI.lrcThemeBtn) UI.lrcThemeBtn.innerHTML = ICONS[`theme_${lyricsConfig.theme}`];

        if (UI.floatLyricsText) {
            UI.floatLyricsText.classList.remove('theme-light', 'theme-dark');
            UI.floatLyricsText.classList.add(`theme-${lyricsConfig.theme}`);
        }
