    function extractExcludes(str) {
        let excludes = [];
        let cleanStr = str.replace(/<([^>]+)>/g, (match, p1) => {
            const trimmed = p1.trim();
            if (trimmed) {
                excludes.push(trimmed);
                const parts = trimmed.split(/\s+/).filter(Boolean);
                if (parts.length > 1) {
                    excludes.push(...parts);
                }
            }
            return '';
        });
        return { cleanStr: cleanStr.trim(), excludes };
    }

    // 精准匹配搜索逻辑
    async function searchBestMatchTrack(title, artist) {
        if (!title) return null;
        try {
            const titleRes = extractExcludes(title || '');
            const artistRes = extractExcludes(artist || '');
            const excludes = [...titleRes.excludes, ...artistRes.excludes];
            const cleanTitle = titleRes.cleanStr;
            const cleanArtist = artistRes.cleanStr;

            const fetchSearch = async (kw) => {
                const rawSearchUrl = `https://music-api.gdstudio.xyz/api.php?types=search&source=netease&name=${encodeURIComponent(kw)}&count=5&pages=1`;
                try {
                    // 优先直连
                    const res = await fetch(rawSearchUrl);
                    return await res.json();
                } catch (e) {
                    // 失败则走代理
                    const searchUrl = `https://corsproxy.io/?${encodeURIComponent(rawSearchUrl)}`;
                    const searchRes = await fetch(searchUrl);
                    return await searchRes.json();
                }
            };

            const keyword = `${cleanTitle} ${cleanArtist || ''}`.trim();
            let searchData = [];

            try {
                searchData = await fetchSearch(keyword);
            } catch (e) {
                console.warn('[MusicPlayer] Initial search failed:', e);
            }

            // 如果返回空，尝试全小写和简繁转换，沟槽的分词器你把我害惨了
            const normalizedKeyword = normalizeStr(keyword);
            if ((!searchData || searchData.length === 0) && keyword !== normalizedKeyword) {
                try {
                    searchData = await fetchSearch(normalizedKeyword);
                } catch (e) {}
            }
            // 如果还返回空，尝试只搜歌名作为兜底
            if ((!searchData || searchData.length === 0) && cleanArtist) {
                try {
                    searchData = await fetchSearch(normalizeStr(cleanTitle));
                } catch (e) {}
            }

            if (!searchData || !Array.isArray(searchData) || searchData.length === 0) return null;

            const targetTitle = normalizeStr(cleanTitle);
            // 剔除各种常见的分隔符，统一为空格
            const normalizeArtistStr = (str) => normalizeStr(str).replace(/[&,、\/|]/g, ' ').replace(/\s+/g, ' ').trim();
            const targetArtist = normalizeArtistStr(cleanArtist || '');

            // 为每个结果打分
            const scoredTracks = searchData.map(track => {
                let score = 100;
                const trackName = normalizeStr(track.name || '');
                const rawTrackArtist = Array.isArray(track.artist) ? track.artist.join(' ') : (track.artist || '');
                const trackArtist = normalizeArtistStr(rawTrackArtist);

                // 1. 标题完全匹配加分
                if (trackName === targetTitle) {
                    score += 50;
                } else if (trackName.includes(targetTitle) || targetTitle.includes(trackName)) {
                    score += 20;
                } else {
                    score -= 30;
                }
                // 2. 歌手完全匹配加分
                if (targetArtist) {
                    if (trackArtist === targetArtist) {
                        score += 50;
                    } else if (trackArtist.includes(targetArtist) || targetArtist.includes(trackArtist)) {
                        score += 20;
                    } else {
                        score -= 10; // 歌手不匹配扣分
                    }
                }

                // 3. 排除关键词扣分
                if (excludes.length > 0) {
                    let hasExclude = false;
                    for (let i = 0; i < excludes.length; i++) {
                        const normEx = normalizeStr(excludes[i]);
                        if (trackName.includes(normEx) || trackArtist.includes(normEx)) {
                            hasExclude = true;
                            break;
                        }
                    }
                    if (hasExclude) {
                        score -= 200;
                    }
                }

                return { ...track, _score: score };
            });

            // 按照分数从高到低排序
            scoredTracks.sort((a, b) => b._score - a._score);
            console.log('[MusicPlayer] Search candidates:', scoredTracks.map(t => `${t.name} - ${t.artist} (${t._score})`));

            // 返回得分最高的那一个
            return scoredTracks[0];


        } catch (e) {
            console.warn('[MusicPlayer] Search API failed:', e);
            return null;
        }
    }

    // 获取歌词
    async function fetchAndRenderLyrics() {
        if (!isLyricsEnabled) return;

        const renderingKey = currentKey;
        const music = MUSIC_CONFIG[renderingKey];
        if (!music || !music.title) return;

        // 如果配置了禁用歌词
        if (music.noLyrics) {
            if (UI.lyricsContent) UI.lyricsContent.innerHTML = '<div style="padding:20px;">...</div>';
            if (UI.floatLyricsText) UI.floatLyricsText.innerHTML = '';
            lyricsData = [];
            UI.lyricsLines = [];
            return;
        }

        if (UI.lyricsContent) UI.lyricsContent.innerHTML = '<div style="padding:20px;">搜索歌词资源...</div>';
        if (UI.floatLyricsText) UI.floatLyricsText.innerHTML = '<span style="font-size:12px">...</span>';
        lyricsData = [];
        UI.lyricsLines = [];

        let foundLrc = null;
        let foundTrans = null;

        try {
            // 如果缓存里有上次搜索存下来的最优匹配 lyric_id，直接用
            let lyricId = music._cachedLyricId;

            if (!lyricId) {
                const bestTrack = await searchBestMatchTrack(music.rawTitle || music.title, music.rawArtist || music.artist);
                if (bestTrack) {
                    lyricId = bestTrack.lyric_id;
                    music._cachedLyricId = lyricId; // 顺手缓存一下
                }
            }

            // 获取歌词
            if (lyricId) {
                const rawLrcUrl = `https://music-api.gdstudio.xyz/api.php?types=lyric&source=netease&id=${lyricId}`;
                let lrcData = null;
                try {
                    const lrcRes = await fetch(rawLrcUrl);
                    lrcData = await lrcRes.json();
                } catch (e) {
                    const lrcUrl = `https://corsproxy.io/?${encodeURIComponent(rawLrcUrl)}`;
                    const lrcRes = await fetch(lrcUrl);
                    lrcData = await lrcRes.json();
                }

                if (lrcData && lrcData.lyric) {
                    foundLrc = lrcData.lyric;
                    foundTrans = lrcData.tlyric || null;
                }
            }
        } catch (err) {
            console.warn('[MusicPlayer] GDStudio API fetch failed:', err);
        }

        // 防止异步请求回来时已经切歌
        if (renderingKey !== currentKey) return;

        if (foundLrc) {
            parseLyrics(foundLrc, foundTrans);
            renderLyricsPanel();
            // 强制重新同步一次
            startLyricsSync();
        } else {
             if (UI.lyricsContent) UI.lyricsContent.innerHTML = '<div style="padding:20px;">未找到歌词资源</div>';
             if (UI.floatLyricsText) UI.floatLyricsText.innerHTML = '<span style="font-size:12px">未找到歌词资源</span>';
        }
    }

    function parseLyrics(lrcText, tLrcText) {
        lyricsData = [];
        const regex = /^\s*\[(\d{1,3}):(\d{1,2})(?:[:\.](\d{1,3}))?\]([\s\S]*)/;

        // 解析主歌词
        const parse = (text) => {
            const map = new Map();
            if (!text) return map;
            text.split('\n').forEach(line => {
                // 提前去除首尾的 \r 和空白字符，防止干扰正则
                line = line.trim();
                if (!line) return;

                const match = line.match(regex);
                if (match) {
                    const min = parseInt(match[1], 10);
                    const sec = parseInt(match[2], 10);
                    const msStr = match[3] ? match[3].padEnd(3, '0') : '000';
                    const ms = parseInt(msStr, 10);
                    const time = min * 60 + sec + ms / 1000;
                    const content = match[4].trim();
                    if (content) map.set(time.toFixed(3), content); // 使用字符串key避免浮点误差
                }
            });
            return map;
        };

        const lrcMap = parse(lrcText);
        const tLrcMap = parse(tLrcText);

        // 合并
        const sortedTimes = Array.from(lrcMap.keys()).sort((a, b) => parseFloat(a) - parseFloat(b));

        sortedTimes.forEach(timeStr => {
            lyricsData.push({
                time: parseFloat(timeStr),
                text: lrcMap.get(timeStr),
                trans: tLrcMap.get(timeStr) || ''
            });
        });
    }

    function renderLyricsPanel() {
        const content = UI.lyricsContent;
        if (!content) return;
        content.innerHTML = '';

        // 前后空白
        const padding = doc.createElement('div');
        padding.style.height = '60px';
        content.appendChild(padding.cloneNode());

        UI.lyricsLines = [];

        lyricsData.forEach((line, index) => {
            const div = doc.createElement('div');
            div.className = 'th-mp-lyrics-line';
            div.dataset.index = index;

            // 彩蛋
            let processedText = line.text;
            const loveKeywords = ['爱情', '愛情', 'love', 'Love', 'LOVE', '爱', '愛', '사랑'];
            loveKeywords.forEach(kw => {
                 processedText = processedText.replace(new RegExp(kw, 'g'), `<span class="th-mp-lyrics-tint">${kw}</span>`);
            });

            div.innerHTML = `<div>${processedText}</div>${line.trans ? `<div style="font-size:11px;opacity:0.7">${line.trans}</div>` : ''}`;
            content.appendChild(div);
            UI.lyricsLines.push(div);
        });

        content.appendChild(padding.cloneNode());
    }

    function escapeHtml(str) {
        return (str || '').toString()
            .replace(/&/g, "&amp;")
            .replace(/</g, "&lt;")
            .replace(/>/g, "&gt;")
            .replace(/"/g, "&quot;")
            .replace(/'/g, "&#039;");
    }

    // 渲染播放列表
    function renderPlaylist() {
        const panel = UI.playlistList;
        if (!panel) return;
        panel.innerHTML = '';

        Object.keys(MUSIC_CONFIG).filter(k => k !== 'null').forEach(key => {
            const track = MUSIC_CONFIG[key];
            const item = doc.createElement('div');
            item.className = `th-mp-playlist-item ${key === currentKey ? 'active' : ''}`;

            const isDeletable = key !== 'default';

            item.innerHTML = `
                <div class="th-mp-playlist-info">
                    <span style="font-weight:bold;white-space:nowrap;">${escapeHtml(track.title)}</span>
                    <span style="font-size:0.9em;opacity:0.8;text-overflow:ellipsis;overflow:hidden;white-space:nowrap;">${escapeHtml(track.artist)}</span>
                </div>
                ${isDeletable ? `<div class="th-mp-playlist-del" title="从列表中移除">${ICONS.delete}</div>` : ''}
            `;

            item.addEventListener('click', (e) => {
                 playTrackByKey(key);
                 togglePlaylist();
            });

            if (isDeletable) {
                const delBtn = item.querySelector('.th-mp-playlist-del');
                if (delBtn) {
                    delBtn.addEventListener('click', (e) => {
                        e.stopPropagation();
                        deleteFromPlaylist(key);
                    });
                }
            }

            panel.appendChild(item);
        });

    }

    function deleteFromPlaylist(key) {
        if (!MUSIC_CONFIG[key]) return;

        const keys = Object.keys(MUSIC_CONFIG).filter(k => k !== 'null');

        // 如果删除的是当前播放的歌曲
        if (currentKey === key) {
            if (keys.length > 1) {
                const idx = keys.indexOf(key);
                const nextIdx = (idx + 1) % keys.length;
                const nextKey = keys[nextIdx];

                delete MUSIC_CONFIG[key];

                // 播放下一首
                playTrackByKey(nextKey);
            } else {
                // 只剩这一首，清空
                delete MUSIC_CONFIG[key];
                if (bgmPlayer) {
                    bgmPlayer.pause();
                    bgmPlayer.removeAttribute('src');
                    bgmPlayer.load();
                }
                updateUIInfo({title: '未播放', artist: ''});
                currentKey = 'default';
            }
        } else {
            // 删除非当前播放歌曲
            delete MUSIC_CONFIG[key];
        }

        renderPlaylist();
        if (typeof toastr !== 'undefined') toastr.success('已从播放列表中移除');
    }

    async function parseAndAddPlaylist(playlistId, isStartup = false) {
        if (!isStartup && typeof toastr !== 'undefined') toastr.info('正在解析歌单，请稍候...');
        try {
            let parsedTracks = [];

            const fetchSources = [
                // 1. Meting API
                async () => {
                    const res = await fetch(`https://api.injahow.cn/meting/?server=netease&type=playlist&id=${playlistId}`);
                    const data = await res.json();
                    if (Array.isArray(data) && data.length > 0) {
                        return data.map(t => ({ name: t.name, artist: t.artist || t.author }));
                    }
                    throw new Error('Meting returned empty or invalid format');
                },
                // 官方 API
                async () => {
                    const apiUrl = `https://music.163.com/api/playlist/detail?id=${playlistId}`;
                    const res = await fetch(`https://corsproxy.io/?${encodeURIComponent(apiUrl)}`);
                    const data = await res.json();
                    let tracks = [];
                    if (data && data.playlist && data.playlist.tracks) tracks = data.playlist.tracks;
                    else if (data && data.result && data.result.tracks) tracks = data.result.tracks;

                    if (tracks.length > 0) {
                        return tracks.map(track => ({
                            name: track.name,
                            artist: (track.artists || track.ar || []).map(a => a.name).join(' / ')
                        }));
                    }
                    throw new Error('Official API returned empty');
                }
            ];

            for (let i = 0; i < fetchSources.length; i++) {
                try {
                    parsedTracks = await fetchSources[i]();
                    if (parsedTracks && parsedTracks.length > 0) {
                        console.log(`[MusicPlayer] Playlist parsed successfully from source ${i + 1}`);
                        break;
                    }
                } catch (e) {
                    console.warn(`[MusicPlayer] Playlist source ${i + 1} failed:`, e);
                }
            }

            if (parsedTracks && parsedTracks.length > 0) {
                let addedCount = 0;
                let firstNewKey = null;
                parsedTracks.forEach(track => {
                    if (track.name) {
                        const newKey = addMusicToPlaylist(track.name, track.artist || '', true);
                        if (newKey && !firstNewKey) firstNewKey = newKey;
                        addedCount++;
                    }
                });

                if (addedCount > 0) {
                    renderPlaylist();
                    if (typeof toastr !== 'undefined') toastr.success(`成功导入歌单，共 ${addedCount} 首歌曲`);

                    // 只有在非启动状态下才自动播放，启动状态下由 start 里的延迟逻辑接管以防止覆盖上次播放记录
                    if (!isStartup && (!bgmPlayer || bgmPlayer.paused) && isPlayerVisible && firstNewKey) {
                        playTrackByKey(firstNewKey);
                    }
                    return true;
                } else {
                    if (!isStartup && typeof toastr !== 'undefined') toastr.warning('歌单中没有可用的歌曲');
                    return false;
                }
            } else {
                if (!isStartup && typeof toastr !== 'undefined') toastr.error('所有解析均失败');
                return false;
            }
        } catch (err) {
            console.error('[MusicPlayer] Parse playlist failed:', err);
            if (!isStartup && typeof toastr !== 'undefined') toastr.error('解析歌单失败，请检查网络或链接');
            return false;
        }
    }

    function addMusicToPlaylist(title, artist, silent = false) {
        const titleRes = extractExcludes(title || '');
        const artistRes = extractExcludes(artist || '');
        const cleanTitle = titleRes.cleanStr;
        const cleanArtist = artistRes.cleanStr;

        // 查重：检查是否已存在相同的歌名和歌手（支持多语/简繁忽略）
        const exists = Object.keys(MUSIC_CONFIG).find(k => {
            const track = MUSIC_CONFIG[k];
            const matchRaw = track.rawTitle && normalizeStr(track.rawTitle) === normalizeStr(title) &&
                             normalizeStr(track.rawArtist || '') === normalizeStr(artist || '');
            const matchCur = normalizeStr(track.title) === normalizeStr(cleanTitle) &&
                             normalizeStr(track.artist || '') === normalizeStr(cleanArtist || '');
            return matchRaw || matchCur;
        });

        if (exists) {
            console.log(`[MusicPlayer] Song already exists: ${title} - ${artist}`);
            return exists; // 返回已存在的 key
        }

        const key = 'd' + Date.now() + Math.floor(Math.random() * 1000);
        MUSIC_CONFIG[key] = {
            title: cleanTitle,
            artist: cleanArtist,
            rawTitle: title,
            rawArtist: artist,
            url: ""
        };
        if (!silent) {
            renderPlaylist();
            if (typeof toastr !== 'undefined') toastr.success(`已添加bgm: ${cleanTitle} - ${cleanArtist}`);
        }
        return key;
    }

    function scanAndAddMusic(text, allowAutoPlay = true) {
        if (!text) return;
        ADD_MUSIC_REGEX.lastIndex = 0;
        const matches = [...text.matchAll(ADD_MUSIC_REGEX)];

        let firstNewKey = null;

        // 处理所有匹配项
        for (const match of matches) {
            const title = match[1].trim();
            const artist = match[2].trim();

            if (title && artist) {
                // 添加并获取 key
                const newKey = addMusicToPlaylist(title, artist);
                if (!firstNewKey) firstNewKey = newKey;
            }
        }

        if (allowAutoPlay && firstNewKey && (!bgmPlayer || bgmPlayer.paused) && isPlayerVisible) {
            console.log(`[MusicPlayer] Auto-playing new track: ${firstNewKey}`);
            playTrackByKey(firstNewKey);
        }
    }

    // 切换曲目
    function switchTrack(direction) {
        const keys = Object.keys(MUSIC_CONFIG).filter(k => k !== 'null');

        if (MODES[currentModeIndex] === 'shuffle') {
            let randomIdx;
            if (keys.length > 1) {
                do {
                    randomIdx = Math.floor(Math.random() * keys.length);
                } while (keys[randomIdx] === currentKey);
            } else {
                randomIdx = 0;
            }
            playTrackByKey(keys[randomIdx]);
            return;
        }

        let idx = keys.indexOf(currentKey);

        if (direction === 'next') {
            idx = (idx + 1) % keys.length;
        } else {
            idx = (idx - 1 + keys.length) % keys.length;
        }

        playTrackByKey(keys[idx]);
    }

    // 自动获取歌曲 URL
    async function getTrackUrl(music) {
        if (music.url) return music.url;

        try {
            console.log('[MusicPlayer] URL empty, searching GDStudio...');

            let bestTrack = null;
            // 如果缓存了ID跳过搜索
            if (music._trackId) {
                bestTrack = { id: music._trackId, lyric_id: music._cachedLyricId };
            } else {
                bestTrack = await searchBestMatchTrack(music.rawTitle || music.title, music.rawArtist || music.artist);
            }

            if (bestTrack && bestTrack.id) {
                 // 缓存歌词ID和歌曲ID，供下次直接使用，避免重复搜索
                 if (bestTrack.lyric_id) {
                     music._cachedLyricId = bestTrack.lyric_id;
                 }
                 music._trackId = bestTrack.id;

                 const rawUrlReq = `https://music-api.gdstudio.xyz/api.php?types=url&source=netease&id=${bestTrack.id}&br=320`;
                 let urlData = null;
                 try {
                     const directRes = await fetch(rawUrlReq);
                     urlData = await directRes.json();
                 } catch (e) {
                     const urlReq = `https://corsproxy.io/?${encodeURIComponent(rawUrlReq)}`;
                     const urlRes = await fetch(urlReq);
                     urlData = await urlRes.json();
                 }

                 // 如果最高分没版权（没有拿到有效 url），尝试备用项？目前 API 好像没版权也会返回假链接，暂且直接返回
                 if (urlData && urlData.url) {
                      if (bestTrack.name) music.title = bestTrack.name;
                      if (bestTrack.artist) {
                          music.artist = Array.isArray(bestTrack.artist)
                              ? bestTrack.artist.map(a => typeof a === 'object' ? (a.name || '') : a).join(' / ')
                              : bestTrack.artist;
                      }

                      return urlData.url;
                 }
            }
        } catch (e) {
            console.warn('[MusicPlayer] Auto-fetch failed:', e);
        }
        return null;
    }

    // 播放指定 Key 的音乐
    async function playTrackByKey(key) {
        if (!isPlayerVisible) return;
        const music = MUSIC_CONFIG[key];
        if (!music) return;

        currentKey = key;

        // 保存当前播放的歌曲信息到浏览器缓存中
        try {
            if (music.title && music.title !== '这里很安静…') {
                localStorage.setItem('th_mp_last_played_track', JSON.stringify({
                    title: music.title,
                    artist: music.artist || ''
                }));
            }
        } catch (e) { console.warn('[MusicPlayer] Failed to save last played track:', e); }

        // 立即更新信息与列表状态
        updateUIInfo(music);
        renderPlaylist();

        let playUrl = music.url;

        // 如果没有 URL，尝试自动获取
        if (!playUrl && music.title) {
            playUrl = await getTrackUrl(music);

            // 防止异步获取期间切歌
            if (currentKey !== key) return;

            if (!playUrl) {
                if (typeof toastr !== 'undefined') {
                    toastr.info(`未找到音源: ${music.title}，点击此处重新加载`, '搜索失败', {
                        timeOut: 8000,
                        extendedTimeOut: 4000,
                        preventDuplicates: true,
                        onclick: () => playTrackByKey(key)
                    });
                }
                return;
            }
            updateUIInfo(music);
            renderPlaylist();
        }

        if (bgmPlayer && playUrl) {
            bgmPlayer.src = playUrl;
            bgmPlayer.play().catch(e => {
                console.error("[MusicPlayer] Playback failed:", e);
                // 忽略 AbortError
                if (e.name === 'AbortError' || !bgmPlayer.paused) return;

                if (typeof toastr !== 'undefined') {
                    toastr.info(`无法播放: ${music.title}，点击此处重试`, '播放失败', {
                        timeOut: 8000,
                        extendedTimeOut: 4000,
                        preventDuplicates: true,
                        onclick: () => playTrackByKey(key)
                    });
                }
            });
            fetchAndRenderLyrics();
            updatePlayStateUI(true);
        }

        const currentSettings = getAudioSettings('bgm');
        if (!currentSettings.mode) {
             const hasNumericIds = Object.keys(MUSIC_CONFIG).some(k => /^\d+$/.test(k));
             setAudioSettings('bgm', { mode: hasNumericIds ? 'repeat_one' : 'repeat_all' });
        }
    }

    // 更新 UI 信息
    function updateUIInfo(music) {
        console.log('[MusicPlayer] Updating UI info...',music);
        if (UI.title) UI.title.innerText = music.title || '未播放';
        if (UI.artist) UI.artist.innerText = music.artist ? `- ${music.artist}` : '';

        if (UI.coverImg) {
            if (music.cover) {
                UI.coverImg.innerHTML = '';
                UI.coverImg.style.backgroundImage = `url('${music.cover}')`;
            } else {
                UI.coverImg.style.backgroundImage = 'none';
                UI.coverImg.innerHTML = ICONS.note;
            }
        }
    }

    // 播放/暂停控制
    function togglePlay() {
        if (bgmPlayer) {
            if (!bgmPlayer.paused) {
                bgmPlayer.pause();
            } else {
                // 如果已有资源且未播放，则恢复播放
                const currentMusic = MUSIC_CONFIG[currentKey];

                // 修复逻辑：允许自动获取 URL 的歌曲（url为空）在暂停后恢复播放
                // 如果 currentMusic.url 有值则校验匹配，否则只要播放器有资源就信任它
                const isUrlMatch = currentMusic && (!currentMusic.url || bgmPlayer.src.includes(currentMusic.url));

                if (bgmPlayer.src && bgmPlayer.src !== window.location.href && isUrlMatch) {
                    bgmPlayer.play().catch(e => console.error("[MusicPlayer] Resume failed:", e));
                } else {
                    // 重新尝试播放（会触发重新搜索）
                    playTrackByKey(currentKey);
                }
            }
        }
    }

    function updatePlayStateUI(playing) {
        isPlaying = playing;

        if (UI.playBtn) UI.playBtn.innerHTML = playing ? ICONS.pause : ICONS.play;

        if (UI.player) {
            if (playing) UI.player.classList.add('playing');
            else UI.player.classList.remove('playing');
        }
    }

    function cycleMode() {
        currentModeIndex = (currentModeIndex + 1) % MODES.length;
        const newMode = MODES[currentModeIndex];
        let modeName = '';
        if (newMode === 'repeat_one'){
            modeName = '单曲循环';
        } else if (newMode === 'repeat_all'){
            modeName = '列表循环';
        } else if (newMode === 'shuffle'){
            modeName = '随机播放';
        }
        setAudioSettings('bgm', { mode: newMode });
        // 存储播放模式
        setScriptVar('play_mode', newMode);

        if(UI.modeBtn) {
            let icon = ICONS.mode_repeat_one;
            if (newMode === 'repeat_all') icon = ICONS.mode_repeat_all;
            else if (newMode === 'shuffle') icon = ICONS.mode_shuffle;
            UI.modeBtn.innerHTML = icon;
        }
        toastr.success(`已切换播放模式: ${modeName}`);
    }

    function syncUIWithSettings() {
        try {
            const settings = getAudioSettings('bgm');
            // 优先从变量读取模式，如果没有则从 settings 读取
            const savedMode = getScriptVar('play_mode');
            const currentMode = savedMode || settings.mode;

            // 如果变量里有存模式，但当前 settings 不一致，则同步过去
            if (savedMode && settings.mode !== savedMode) {
                 setAudioSettings('bgm', { mode: savedMode });
            }

            const modeIndex = MODES.indexOf(currentMode);
            if (modeIndex !== -1) {
                currentModeIndex = modeIndex;
                if(UI.modeBtn) {
                    let icon = ICONS.mode_repeat_one;
                    if (settings.mode === 'repeat_all') icon = ICONS.mode_repeat_all;
                    else if (settings.mode === 'shuffle') icon = ICONS.mode_shuffle;
                    UI.modeBtn.innerHTML = icon;
                }
            }

            if (bgmPlayer) {
                bgmPlayer.volume = (settings.volume ?? 100) / 100;
                bgmPlayer.muted = settings.muted;
            }
        } catch (e) { console.error(e); }
    }

    // 自动播放逻辑
    async function checkAndPlayOpeningBGM() {
        try {
            if (!isPlayerVisible) return;
            // 检查是否存在数字ID
            const hasNumericIds = Object.keys(MUSIC_CONFIG).some(k => /^\d+$/.test(k));

            // 模式分支：无视开场白
            if (!hasNumericIds) {
                // 如果已经在播放，或者是用户手动暂停（非初始状态），则不干预
                if (bgmPlayer && bgmPlayer.src && bgmPlayer.paused && bgmPlayer.currentTime > 0) return;
                if (bgmPlayer && !bgmPlayer.paused) return;

                const keys = Object.keys(MUSIC_CONFIG).filter(k => k !== 'null');
                if (keys.length === 0) return;

                // 优先播放当前选中的，否则播放第一个
                const targetKey = (currentKey && MUSIC_CONFIG[currentKey]) ? currentKey : keys[0];

                playTrackByKey(targetKey);
                return;
            }

            // 模式2：关联开场白
            const messages = getChatMessages(0);
            if (!messages || messages.length === 0) return;
            const firstMes = messages[0];
            const swipeId = String(firstMes.swipe_id || 0);

            // 如果开场白没有变化，则不打断当前播放
            if (swipeId === lastOpeningSwipeId) return;
            lastOpeningSwipeId = swipeId;

            console.log(`[MusicPlayer] Swipe ID: ${swipeId}`);

            if (SILENT_OPENINGS.includes(swipeId)) {
                console.log(`[MusicPlayer] ${swipeId} Stopping playback.`);
                if (bgmPlayer && !bgmPlayer.paused) {
                    bgmPlayer.pause();
                    updatePlayStateUI(false);
                }
                updateUIInfo(MUSIC_CONFIG['null']);

                if (isLyricsEnabled) {
                    if (UI.floatLyricsText) UI.floatLyricsText.innerHTML = '';
                    if (UI.lyricsContent) UI.lyricsContent.innerHTML = '';
                    lyricsData = [];
                    UI.lyricsLines = [];
                }
                return;
            }

            const targetKey = MUSIC_CONFIG[swipeId] ? swipeId : 'default';

            // 如果目标曲目与当前一致，且播放器已有资源（正在播放或暂停），则跳过以防打断
            if (targetKey === currentKey && bgmPlayer && bgmPlayer.src) {
                return;
            }

            playTrackByKey(targetKey);
        } catch (e) { console.error(e); }
    }

    // ================= 事件监听 =================

    let scanTimer = null;
    const onMessageChange = (messageId) => {
        if (messageId === 0) setTimeout(checkAndPlayOpeningBGM, 100);

        let allowAutoPlay = false;
        try {
            const contextChat = window.parent.chat;
            if (contextChat && Array.isArray(contextChat)) {
                if (messageId === contextChat.length - 1) {
                    allowAutoPlay = true;
                }
            } else {
                allowAutoPlay = false;
            }
        } catch(e) { }

        // 扫描回复中的点歌指令
        if (scanTimer) clearTimeout(scanTimer);
        scanTimer = setTimeout(() => {
            try {
                // 获取当前消息
                const msgs = getChatMessages(messageId);
                if (msgs && msgs.length > 0) {
                    const msg = msgs[0];
                    // 仅处理 AI 回复 (assistant) 或非用户消息
                    if (msg.role === 'assistant' || (msg.is_user === false)) {
                         const content = msg.message || msg.mes;
                         scanAndAddMusic(content, allowAutoPlay);
                    }
                }
            } catch(e) { console.warn('[MusicPlayer] Scan failed:', e); }
        }, 2000);
    };

    eventOn(tavern_events.MESSAGE_SWIPED, onMessageChange);
    eventOn(tavern_events.MESSAGE_UPDATED, onMessageChange);
    eventOn(tavern_events.CHARACTER_MESSAGE_RENDERED, onMessageChange);
    eventOn(tavern_events.MESSAGE_RECEIVED, onMessageChange);

    eventOn(tavern_events.SETTINGS_UPDATED, syncUIWithSettings);

    eventOn(tavern_events.CHAT_CHANGED, () => {
        lastOpeningSwipeId = null;
        setTimeout(checkAndPlayOpeningBGM, 500);
    });

    // ================= 初始化内部播放器 =================
    function initInternalPlayer() {
        if (window.parent._th_custom_bgm_player) {
            bgmPlayer = window.parent._th_custom_bgm_player;
        } else {
            bgmPlayer = new window.parent.Audio();
            window.parent._th_custom_bgm_player = bgmPlayer;
        }

        // 绑定事件：播放结束自动切歌
        bgmPlayer.onended = () => {
            if (MODES[currentModeIndex] === 'repeat_one') {
                bgmPlayer.currentTime = 0;
                bgmPlayer.play();
            } else {
                switchTrack('next');
            }
        };

        // 绑定事件：更新UI状态
        bgmPlayer.onplay = () => {
            updatePlayStateUI(true);
            startLyricsSync();
        };
        bgmPlayer.onpause = () => {
            updatePlayStateUI(false);
            stopLyricsSync();
        };

        syncUIWithSettings();
    }

    function startLyricsSync() {
        stopLyricsSync();
        lastActiveIndex = -1; // 重新同步时重置
        lyricsTimer = requestAnimationFrame(updateLyricsLoop);
    }

    function stopLyricsSync() {
        if (lyricsTimer) {
            cancelAnimationFrame(lyricsTimer);
            lyricsTimer = null;
        }
    }

    // 缩减重绘与查询
    function updateLyricsLoop() {
        if (!bgmPlayer || bgmPlayer.paused || !isLyricsEnabled || lyricsData.length === 0) {
            return;
        }

        const currentTime = bgmPlayer.currentTime;
        let activeIndex = -1;

        // 倒序查找（因时间多是递增，命中更快）
        for (let i = lyricsData.length - 1; i >= 0; i--) {
            if (currentTime >= lyricsData[i].time) {
                activeIndex = i;
                break;
            }
        }

        // 仅当所在的歌词行发生变化时，才触发 DOM 变更
        if (activeIndex !== -1 && activeIndex !== lastActiveIndex) {
            lastActiveIndex = activeIndex;
            const lineData = lyricsData[activeIndex];
            const floatText = UI.floatLyricsText;

            // 更新浮动歌词
            if (floatText) {
                floatText.dataset.lastTime = String(lineData.time);

                // 拆分字符产生动效
                let charsHtml = '';
                let charIndex = 0;

                // 按英文单词分割，保留分隔符
                // 匹配连续的字母数字（含连字符），将其视为一个整体单词包裹，防止换行断词
                const parts = lineData.text.split(/([a-zA-Z0-9']+(?:-[a-zA-Z0-9']+)*)/);

                parts.forEach(part => {
                    if (!part) return;

                    const isWord = /^[a-zA-Z0-9']+(?:-[a-zA-Z0-9']+)*$/.test(part);
                    if (isWord) charsHtml += '<span style="display:inline-block; white-space:nowrap">';

                    for (const char of part) {
                        const i = charIndex++;

                        if (char === ' ') {
                            charsHtml += ' ';
                            continue;
                        }

                        const rx = (Math.random() - 0.5) * 40 + 'px';
                        const ry = (Math.random() - 0.5) * 30 + 'px';
                        const rr = (Math.random() - 0.5) * 60 + 'deg';
                        const delay = Math.random() * 0.2 + (i * 0.03) + 's';

                        // 彩蛋检测
                        const loveChars = ['爱', '愛'];
                        let isLove = loveChars.includes(char);
                        if (!isLove) {
                             const text = lineData.text;
                             const patterns = ['love', 'Love', 'LOVE', '사랑', '爱情', '愛情'];
                             for (let p of patterns) {
                                 const idx = text.indexOf(p);
                                 if (idx !== -1 && i >= idx && i < idx + p.length) {
                                     isLove = true;
                                     break;
                                 }
                             }
                        }

                        const loveClass = isLove ? 'th-mp-lyrics-tint' : '';
                        charsHtml += `<span class="th-pv-char ${loveClass}" style="--rx:${rx};--ry:${ry};--rr:${rr};animation-delay:${delay}">${char}</span>`;
                    }

                    if (isWord) charsHtml += '</span>';
                });

                let html = `<div>${charsHtml}</div>`;
                if (lineData.trans) {
                    html += `<div class="th-mp-float-line-sub th-pv-char" style="animation-delay: 0.5s">${lineData.trans}</div>`;
                }
                floatText.innerHTML = html;
            }

            // 更新面板滚动
            if (UI.lyricsLines && UI.lyricsLines[activeIndex]) {
                const activeLine = UI.lyricsLines[activeIndex];
                if (!activeLine.classList.contains('active')) {
                    UI.lyricsLines.forEach(l => l.classList.remove('active'));
                    activeLine.classList.add('active');
                    scrollToLyricsLine(activeLine);
                }
            }
        }

        lyricsTimer = requestAnimationFrame(updateLyricsLoop);
    }

    // ================= 启动 =================

    async function start() {
        console.log('[MusicPlayer] Starting...');
        initStyles();
        if (isPlayerVisible) {
            createPlayerUI();
        }
        initInternalPlayer();

        let loadedFromDefault = false;
        // 如果配置了默认歌单，在启动时自动解析并加载
        if (DEFAULT_PLAYLIST_URL && DEFAULT_PLAYLIST_URL.trim()) {
            const idMatch = DEFAULT_PLAYLIST_URL.match(/music\.163\.com.*?(?:id=)(\d+)/i);
            if (idMatch) {
                console.log(`[MusicPlayer] Loading default playlist: ${idMatch[1]}`);
                loadedFromDefault = await parseAndAddPlaylist(idMatch[1], true);
            }
        }

        // 尝试恢复上次播放的歌曲
        setTimeout(() => {
            let restored = false;
            try {
                const lastPlayedStr = localStorage.getItem('th_mp_last_played_track');
                if (lastPlayedStr) {
                    const lastPlayed = JSON.parse(lastPlayedStr);
                    if (lastPlayed && lastPlayed.title) {
                        // 在当前播放列表中寻找匹配的歌曲
                        const keys = Object.keys(MUSIC_CONFIG).filter(k => k !== 'null');
                        const targetKey = keys.find(k => {
                            const track = MUSIC_CONFIG[k];
                            const matchCur = normalizeStr(track.title) === normalizeStr(lastPlayed.title) &&
                                             normalizeStr(track.artist || '') === normalizeStr(lastPlayed.artist || '');
                            const matchRaw = track.rawTitle && normalizeStr(track.rawTitle) === normalizeStr(lastPlayed.title) &&
                                             normalizeStr(track.rawArtist || '') === normalizeStr(lastPlayed.artist || '');
                            return matchCur || matchRaw;
                        });

                        if (targetKey) {
                            console.log(`[MusicPlayer] Resuming last played track: ${lastPlayed.title}`);
                            playTrackByKey(targetKey);
                            restored = true;
                        }
                    }
                }
            } catch (e) { console.warn('[MusicPlayer] Failed to restore last played track:', e); }

            // 如果没能恢复上次播放的歌，而且是从默认歌单加载的，那就播放列表里的第一首
            if (!restored && loadedFromDefault) {
                const keys = Object.keys(MUSIC_CONFIG).filter(k => k !== 'null');
                if (keys.length > 0) {
                    playTrackByKey(keys[0]);
                }
            }
        }, 1200);

        // 监听脚本被关闭/卸载事件
        window.addEventListener('pagehide', () => {
            console.log('[MusicPlayer] Script unloaded. Cleaning up...');
            if (UI.player) {
                if (UI.player._onDocClick) doc.removeEventListener('click', UI.player._onDocClick);
                UI.player.remove();
            }
            if (UI._onResize) window.removeEventListener('resize', UI._onResize);

            const style = doc.getElementById(STYLE_ID);
            if (style) style.remove();

            if (bgmPlayer) bgmPlayer.pause();

            stopLyricsSync();
            if (scanTimer) clearTimeout(scanTimer);
            if (idleTimer) clearTimeout(idleTimer);
        });
    }

    start();

})();

